const item = $input.first().json;
const analysisText = item.output || item.text || item.analysisText || item.message || item.response || Object.values(item).find(v => typeof v === 'string' && v.length > 100);

function parseResumeAnalysis(text) {
  const result = {
    name: null,
    email: null,
    phone: null,       // <-- added
    skills: [],
    experience: [],
    projects: [],
    fitScore: null,
    status: null,
    summary: null
  };

  // --- NAME ---
  const nameMatch = text.match(/\*\*Name:\*\*\s*(.+)/i);
  if (nameMatch) result.name = nameMatch[1].trim();

  // --- EMAIL ---
  const emailMatch = text.match(/[\w.-]+@[\w.-]+\.\w+/);
  if (emailMatch) result.email = emailMatch[0].trim();

  // --- PHONE ---
  const phoneMatch = text.match(/(\+?[\d\s\-\(\)]{7,15}\d)/);
  if (phoneMatch) result.phone = phoneMatch[1].trim();

  // --- SKILLS ---
  const skillsMatch = text.match(/\*\*Main Skills[:\*\s]*\*?\s*([\s\S]*?)(?=\*\*Years|\*\*Experience|\n\n\*\*)/i);
  if (skillsMatch) {
    const rawSkills = skillsMatch[1].replace(/\*\*/g, '').replace(/\*\s+\*\*Role:\*\*[^\n]*/g, '');
    result.skills = rawSkills
      .split(/[,\n]/)
      .map(s => s.replace(/^\s*[\*\-\(]\s*/, '').replace(/\)\s*$/, '').trim())
      .filter(s => s.length > 1 && !/^role$/i.test(s));
  }

  // --- EXPERIENCE ---
  const expSection = text.match(/\*\*Years of Experience:\*\*([\s\S]*?)(?=\*\*Projects)/i);
  if (expSection) {
    const expLines = expSection[1].match(/\*\s+\*\*(.+?):\*\*\s*(.+)/g) || [];
    result.experience = expLines.map(line => {
      const m = line.match(/\*\s+\*\*(.+?):\*\*\s*(.+)/);
      return m ? { type: m[1].trim(), detail: m[2].trim() } : null;
    }).filter(Boolean);

    if (result.experience.length === 0) {
      result.experience = expSection[1]
        .split('\n')
        .map(l => l.replace(/\*+/g, '').trim())
        .filter(l => l.length > 0);
    }
  }

  // --- PROJECTS ---
  const projectsSection = text.match(/\*\*Projects[\s\S]*?:\*\*([\s\S]*?)(?=\*\*Fit Score|\*\*Fit)/i);
  if (projectsSection) {
    const projectMatches = projectsSection[1].matchAll(/\*\s+\*\*(.+?):\*\*\s*([\s\S]*?)(?=\n\s*\*\s+\*\*|\n\n|$)/g);
    for (const match of projectMatches) {
      result.projects.push({
        name: match[1].trim(),
        description: match[2].replace(/\n/g, ' ').trim()
      });
    }
  }

  // --- FIT SCORE ---
  const fitPatterns = [
    /\*\*(\d+(?:\.\d+)?)\s*\/\s*10\*\*/,
    /\*\*Fit Score[^:]*:\*\*\s*(\d+(?:\.\d+)?)/i,
    /Fit Score[^:]*:\s*\*?\*?(\d+(?:\.\d+)?)/i,
    /(\d+(?:\.\d+)?)\s*\/\s*10/
  ];
  for (const pattern of fitPatterns) {
    const m = text.match(pattern);
    if (m) { result.fitScore = parseFloat(m[1]); break; }
  }

  // --- STATUS ---
  if (result.fitScore !== null && !isNaN(result.fitScore)) {
    if (result.fitScore >= 8)      result.status = 'Strong Candidate';
    else if (result.fitScore >= 6) result.status = 'Potential Candidate';
    else                           result.status = 'Not Recommended';
  } else {
    result.status = 'Unable to Determine';
  }

  // --- SUMMARY ---
  const summaryMatch = text.match(/\*\*Short Summary[^:]*:\*\*\s*([\s\S]+)/i);
  if (summaryMatch) result.summary = summaryMatch[1].replace(/\*\*/g, '').trim();

  return result;
}

const extracted = parseResumeAnalysis(analysisText);
return [{ json: extracted }];

// Final working subject/body splitter for AI Agent output in n8n
return [
{
json: (() => {
const data = $json;
const aiOutput = data.aiEmailContent || data.output || "";

// Convert escaped newlines (\\n) into real ones
const normalized = aiOutput.replace(/\\n/g, "\n").trim();

// --- Extract the subject (after "Subject:" until a line break or "Body:")
const subjectMatch = normalized.match(/Subject\s*:\s*(.*?)(?:\n|$)/i);
const subject = subjectMatch ? subjectMatch[1].trim() : "Interview Invitation";

// --- Extract everything after "Body:" as the email body
let body = "";
const bodyMatch = normalized.match(/Body\s*:\s*([\s\S]*)/i);
if (bodyMatch && bodyMatch[1]) {
body = bodyMatch[1].trim();
} else {

// Fallback: everything after the subject if "Body:" not found
const subjectEndIndex = subjectMatch ? normalized.indexOf(subjectMatch[0]) + subjectMatch[0].length :
0;
body = normalized.slice(subjectEndIndex).trim();
}

// --- Clean up line breaks for better readability
body = body.replace(/\n{2,}/g, "\n\n");

// --- Return structured data
return {
candidateName: data["Candidate Name"],
recommendedRoleTitle: data["Recommended Role Title"],
subject,
body,
};
})(),
},
];

